import { writeOutput } from "./codegen";

const DOCS_URL = "https://developer.garmin.com/gc-developer-program/";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Garmin Connect API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:garmin-connect",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const garminConnectFirewall = {",
    '  name: "garmin-connect",',
    '  description: "Garmin Connect API",',
    "  placeholders: {",
    `    GARMIN_CONNECT_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://apis.garmin.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.GARMIN_CONNECT_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Garmin Connect firewall config...");
  const ts = generateTypeScript();
  writeOutput("garmin-connect", ts, import.meta.dirname);
}
